#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e5+5;
int T;multiset<LL> jian;
_i128 n,m,mx,a[N],b[N],p[N],t[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
_i128 exGCD(_i128 a,_i128 b,_i128 &x,_i128 &y){
    if(b==0){x=1,y=0;return a;}
    _i128 X,Y;
    _i128 yu=exGCD(b,a%b,X,Y);
    x=Y,y=X-Y*(a/b);
    return yu;
}
_i128 QP(_i128 x,_i128 y,_i128 mod){
    _i128 as=1;
    while(y){
        if(y&1)as=as*x%mod;
        x=x*x%mod,y>>=1;
    }return as;
}
void Sol_exCRT(){
    _i128 res=0,mod=1;
    _i128 x=0,y=0,g=0,A=0,B=0,C=0;
    for(LL i=1;i<=n;i++){
        A=b[i]*mod%p[i];B=p[i];
        C=(a[i]-b[i]*res%p[i]+p[i])%p[i];
        g=exGCD(A,B,x,y);
        x=(x%B+B)%B;
        if(C%g!=0){cout<<"-1\n";return;}
        res+=(C/g)*x%(B/g)*mod;
        mod*=(B/g);res%=mod;
    }if(res<mx)res+=((mx-res-1)/mod+1)*mod;
    cout<<(LL)(res)<<"\n";return;
}
int main(){
    T=read();
    while(T--){
        n=read(),m=read();
        jian.clear();mx=0;
        for(LL i=1;i<=n;i++)a[i]=read();
        for(LL i=1;i<=n;i++)p[i]=read();
        for(LL i=1;i<=n;i++)t[i]=read();
        for(LL i=1;i<=m;i++)jian.isr(read());
        for(LL i=1;i<=n;i++){
            auto it=jian.upper_bound(a[i]);
            if(it!=jian.begin())it--;
            b[i]=(*it);
            jian.erase(it),jian.isr(t[i]);
            mx=max(mx,(a[i]-1)/b[i]+1);
        }Sol_exCRT();
    }
    return 0;
}
